60	    ngx_string("200 OK"),
61	    ngx_string("201 Created"),
62	    ngx_string("202 Accepted"),
63	    ngx_null_string,  /* "203 Non-Authoritative Information" */
64	    ngx_string("204 No Content"),
65	    ngx_null_string,  /* "205 Reset Content" */
66	    ngx_string("206 Partial Content"),
67	
68	    /* ngx_null_string, */  /* "207 Multi-Status" */
69	
70	#define NGX_HTTP_LAST_2XX  207
71	#define NGX_HTTP_OFF_3XX   (NGX_HTTP_LAST_2XX - 200)
72	
73	    /* ngx_null_string, */  /* "300 Multiple Choices" */
74	
75	    ngx_string("301 Moved Permanently"),
76	    ngx_string("302 Moved Temporarily"),
77	    ngx_string("303 See Other"),
78	    ngx_string("304 Not Modified"),
