85	#define NGX_HTTP_OFF_4XX   (NGX_HTTP_LAST_3XX - 301 + NGX_HTTP_OFF_3XX)
86	
87	    ngx_string("400 Bad Request"),
88	    ngx_string("401 Unauthorized"),
89	    ngx_string("402 Payment Required"),
