96	    ngx_string("409 Conflict"),
97	    ngx_string("410 Gone"),
98	    ngx_string("411 Length Required"),
99	    ngx_string("412 Precondition Failed"),
100	    ngx_string("413 Request Entity Too Large"),
101	    ngx_string("414 Request-URI Too Large"),
102	    ngx_string("415 Unsupported Media Type"),
103	    ngx_string("416 Requested Range Not Satisfiable"),
104	    ngx_null_string,  /* "417 Expectation Failed" */
