110	    ngx_null_string,  /* "423 Locked" */
111	    ngx_null_string,  /* "424 Failed Dependency" */
112	    ngx_null_string,  /* "425 unused" */
113	    ngx_null_string,  /* "426 Upgrade Required" */
114	    ngx_null_string,  /* "427 unused" */
115	    ngx_null_string,  /* "428 Precondition Required" */
116	    ngx_string("429 Too Many Requests"),
