160	static ngx_int_t
161	ngx_http_header_filter(ngx_http_request_t *r)
162	{
163	    u_char                    *p;
164	    size_t                     len;
165	    ngx_str_t                  host, *status_line;
166	    ngx_buf_t                 *b;
167	    ngx_uint_t                 status, i, port;
168	    ngx_chain_t                out;
169	    ngx_list_part_t           *part;
170	    ngx_table_elt_t           *header;
171	    ngx_connection_t          *c;
172	    ngx_http_core_loc_conf_t  *clcf;
173	    ngx_http_core_srv_conf_t  *cscf;
174	    u_char                     addr[NGX_SOCKADDR_STRLEN];
175	
176	    if (r->header_sent) {
177	        return NGX_OK;
178	    }
179	
180	    r->header_sent = 1;
181	
182	    if (r != r->main) {
183	        return NGX_OK;
184	    }
185	
186	    if (r->http_version < NGX_HTTP_VERSION_10) {
187	        return NGX_OK;
188	    }
189	
190	    if (r->method == NGX_HTTP_HEAD) {
191	        r->header_only = 1;
192	    }
193	
194	    if (r->headers_out.last_modified_time != -1) {
195	        if (r->headers_out.status != NGX_HTTP_OK
196	            && r->headers_out.status != NGX_HTTP_PARTIAL_CONTENT
197	            && r->headers_out.status != NGX_HTTP_NOT_MODIFIED)
198	        {
199	            r->headers_out.last_modified_time = -1;
200	            r->headers_out.last_modified = NULL;
201	        }
202	    }
203	
204	    if (r->keepalive && (ngx_terminate || ngx_exiting)) {
205	        r->keepalive = 0;
206	    }
207	
208	    len = sizeof("HTTP/1.x ") - 1 + sizeof(CRLF) - 1
209	          /* the end of the header */
210	          + sizeof(CRLF) - 1;
211	
212	    /* status line */
213	
214	    if (r->headers_out.status_line.len) {
215	        len += r->headers_out.status_line.len;
216	        status_line = &r->headers_out.status_line;
217	#if (NGX_SUPPRESS_WARN)
218	        status = 0;
219	#endif
220	
221	    } else {
222	
223	        status = r->headers_out.status;
224	
225	        if (status >= NGX_HTTP_OK
226	            && status < NGX_HTTP_LAST_2XX)
227	        {
228	            /* 2XX */
229	
230	            if (status == NGX_HTTP_NO_CONTENT) {
231	                r->header_only = 1;
232	                ngx_str_null(&r->headers_out.content_type);
233	                r->headers_out.last_modified_time = -1;
234	                r->headers_out.last_modified = NULL;
235	                r->headers_out.content_length = NULL;
236	                r->headers_out.content_length_n = -1;
237	            }
238	
239	            status -= NGX_HTTP_OK;
240	            status_line = &ngx_http_status_lines[status];
241	            len += ngx_http_status_lines[status].len;
242	
243	        } else if (status >= NGX_HTTP_MOVED_PERMANENTLY
244	                   && status < NGX_HTTP_LAST_3XX)
245	        {
246	            /* 3XX */
247	
248	            if (status == NGX_HTTP_NOT_MODIFIED) {
249	                r->header_only = 1;
250	            }
251	
252	            status = status - NGX_HTTP_MOVED_PERMANENTLY + NGX_HTTP_OFF_3XX;
253	            status_line = &ngx_http_status_lines[status];
254	            len += ngx_http_status_lines[status].len;
255	
256	        } else if (status >= NGX_HTTP_BAD_REQUEST
257	                   && status < NGX_HTTP_LAST_4XX)
258	        {
259	            /* 4XX */
260	            status = status - NGX_HTTP_BAD_REQUEST
261	                            + NGX_HTTP_OFF_4XX;
262	
263	            status_line = &ngx_http_status_lines[status];
264	            len += ngx_http_status_lines[status].len;
265	
266	        } else if (status >= NGX_HTTP_INTERNAL_SERVER_ERROR
267	                   && status < NGX_HTTP_LAST_5XX)
268	        {
269	            /* 5XX */
270	            status = status - NGX_HTTP_INTERNAL_SERVER_ERROR
271	                            + NGX_HTTP_OFF_5XX;
272	
273	            status_line = &ngx_http_status_lines[status];
274	            len += ngx_http_status_lines[status].len;
275	
276	        } else {
277	            len += NGX_INT_T_LEN + 1 /* SP */;
278	            status_line = NULL;
279	        }
280	
281	        if (status_line && status_line->len == 0) {
282	            status = r->headers_out.status;
283	            len += NGX_INT_T_LEN + 1 /* SP */;
284	            status_line = NULL;
285	        }
286	    }
287	
288	    clcf = ngx_http_get_module_loc_conf(r, ngx_http_core_module);
289	
290	    if (r->headers_out.server == NULL) {
291	        if (clcf->server_tokens == NGX_HTTP_SERVER_TOKENS_ON) {
292	            len += sizeof(ngx_http_server_full_string) - 1;
293	
294	        } else if (clcf->server_tokens == NGX_HTTP_SERVER_TOKENS_BUILD) {
295	            len += sizeof(ngx_http_server_build_string) - 1;
296	
297	        } else {
298	            len += sizeof(ngx_http_server_string) - 1;
299	        }
300	    }
301	
302	    if (r->headers_out.date == NULL) {
303	        len += sizeof("Date: Mon, 28 Sep 1970 06:00:00 GMT" CRLF) - 1;
304	    }
305	
306	    if (r->headers_out.content_type.len) {
307	        len += sizeof("Content-Type: ") - 1
308	               + r->headers_out.content_type.len + 2;
309	
310	        if (r->headers_out.content_type_len == r->headers_out.content_type.len
311	            && r->headers_out.charset.len)
312	        {
313	            len += sizeof("; charset=") - 1 + r->headers_out.charset.len;
314	        }
315	    }
316	
317	    if (r->headers_out.content_length == NULL
318	        && r->headers_out.content_length_n >= 0)
319	    {
320	        len += sizeof("Content-Length: ") - 1 + NGX_OFF_T_LEN + 2;
321	    }
322	
323	    if (r->headers_out.last_modified == NULL
324	        && r->headers_out.last_modified_time != -1)
325	    {
326	        len += sizeof("Last-Modified: Mon, 28 Sep 1970 06:00:00 GMT" CRLF) - 1;
327	    }
328	
329	    c = r->connection;
330	
331	    if (r->headers_out.location
332	        && r->headers_out.location->value.len
333	        && r->headers_out.location->value.data[0] == '/'
334	        && clcf->absolute_redirect)
335	    {
336	        r->headers_out.location->hash = 0;
337	
338	        if (clcf->server_name_in_redirect) {
339	            cscf = ngx_http_get_module_srv_conf(r, ngx_http_core_module);
340	            host = cscf->server_name;
341	
342	        } else if (r->headers_in.server.len) {
343	            host = r->headers_in.server;
344	
345	        } else {
346	            host.len = NGX_SOCKADDR_STRLEN;
347	            host.data = addr;
348	
349	            if (ngx_connection_local_sockaddr(c, &host, 0) != NGX_OK) {
350	                return NGX_ERROR;
351	            }
352	        }
353	
354	        port = ngx_inet_get_port(c->local_sockaddr);
355	
356	        len += sizeof("Location: https://") - 1
357	               + host.len
358	               + r->headers_out.location->value.len + 2;
359	
360	        if (clcf->port_in_redirect) {
361	
362	#if (NGX_HTTP_SSL)
363	            if (c->ssl)
364	                port = (port == 443) ? 0 : port;
365	            else
366	#endif
367	                port = (port == 80) ? 0 : port;
368	
369	        } else {
370	            port = 0;
371	        }
372	
373	        if (port) {
374	            len += sizeof(":65535") - 1;
375	        }
376	
377	    } else {
378	        ngx_str_null(&host);
379	        port = 0;
380	    }
381	
382	    if (r->chunked) {
383	        len += sizeof("Transfer-Encoding: chunked" CRLF) - 1;
384	    }
385	
386	    if (r->headers_out.status == NGX_HTTP_SWITCHING_PROTOCOLS) {
387	        len += sizeof("Connection: upgrade" CRLF) - 1;
388	
389	    } else if (r->keepalive) {
390	        len += sizeof("Connection: keep-alive" CRLF) - 1;
391	
392	        /*
393	         * MSIE and Opera ignore the "Keep-Alive: timeout=<N>" header.
394	         * MSIE keeps the connection alive for about 60-65 seconds.
395	         * Opera keeps the connection alive very long.
396	         * Mozilla keeps the connection alive for N plus about 1-10 seconds.
397	         * Konqueror keeps the connection alive for about N seconds.
398	         */
399	
400	        if (clcf->keepalive_header) {
401	            len += sizeof("Keep-Alive: timeout=") - 1 + NGX_TIME_T_LEN + 2;
402	        }
403	
404	    } else {
405	        len += sizeof("Connection: close" CRLF) - 1;
406	    }
407	
408	#if (NGX_HTTP_GZIP)
409	    if (r->gzip_vary) {
410	        if (clcf->gzip_vary) {
411	            len += sizeof("Vary: Accept-Encoding" CRLF) - 1;
412	
413	        } else {
414	            r->gzip_vary = 0;
415	        }
416	    }
417	#endif
418	
419	    part = &r->headers_out.headers.part;
420	    header = part->elts;
421	
422	    for (i = 0; /* void */; i++) {
423	
424	        if (i >= part->nelts) {
425	            if (part->next == NULL) {
426	                break;
427	            }
428	
429	            part = part->next;
430	            header = part->elts;
431	            i = 0;
432	        }
433	
434	        if (header[i].hash == 0) {
435	            continue;
436	        }
437	
438	        len += header[i].key.len + sizeof(": ") - 1 + header[i].value.len
439	               + sizeof(CRLF) - 1;
440	    }
441	
442	    b = ngx_create_temp_buf(r->pool, len);
443	    if (b == NULL) {
444	        return NGX_ERROR;
445	    }
446	
447	    /* "HTTP/1.x " */
448	    b->last = ngx_cpymem(b->last, "HTTP/1.1 ", sizeof("HTTP/1.x ") - 1);
449	
450	    /* status line */
451	    if (status_line) {
452	        b->last = ngx_copy(b->last, status_line->data, status_line->len);
453	
454	    } else {
455	        b->last = ngx_sprintf(b->last, "%03ui ", status);
456	    }
457	    *b->last++ = CR; *b->last++ = LF;
458	
459	    if (r->headers_out.server == NULL) {
460	        if (clcf->server_tokens == NGX_HTTP_SERVER_TOKENS_ON) {
461	            p = ngx_http_server_full_string;
462	            len = sizeof(ngx_http_server_full_string) - 1;
463	
464	        } else if (clcf->server_tokens == NGX_HTTP_SERVER_TOKENS_BUILD) {
465	            p = ngx_http_server_build_string;
466	            len = sizeof(ngx_http_server_build_string) - 1;
467	
468	        } else {
469	            p = ngx_http_server_string;
470	            len = sizeof(ngx_http_server_string) - 1;
471	        }
472	
473	        b->last = ngx_cpymem(b->last, p, len);
474	    }
475	
476	    if (r->headers_out.date == NULL) {
477	        b->last = ngx_cpymem(b->last, "Date: ", sizeof("Date: ") - 1);
478	        b->last = ngx_cpymem(b->last, ngx_cached_http_time.data,
479	                             ngx_cached_http_time.len);
480	
481	        *b->last++ = CR; *b->last++ = LF;
482	    }
483	
484	    if (r->headers_out.content_type.len) {
485	        b->last = ngx_cpymem(b->last, "Content-Type: ",
486	                             sizeof("Content-Type: ") - 1);
487	        p = b->last;
488	        b->last = ngx_copy(b->last, r->headers_out.content_type.data,
489	                           r->headers_out.content_type.len);
490	
491	        if (r->headers_out.content_type_len == r->headers_out.content_type.len
492	            && r->headers_out.charset.len)
493	        {
494	            b->last = ngx_cpymem(b->last, "; charset=",
495	                                 sizeof("; charset=") - 1);
496	            b->last = ngx_copy(b->last, r->headers_out.charset.data,
497	                               r->headers_out.charset.len);
498	
499	            /* update r->headers_out.content_type for possible logging */
500	
501	            r->headers_out.content_type.len = b->last - p;
502	            r->headers_out.content_type.data = p;
503	        }
504	
505	        *b->last++ = CR; *b->last++ = LF;
506	    }
507	
508	    if (r->headers_out.content_length == NULL
509	        && r->headers_out.content_length_n >= 0)
510	    {
511	        b->last = ngx_sprintf(b->last, "Content-Length: %O" CRLF,
512	                              r->headers_out.content_length_n);
513	    }
514	
515	    if (r->headers_out.last_modified == NULL
516	        && r->headers_out.last_modified_time != -1)
517	    {
518	        b->last = ngx_cpymem(b->last, "Last-Modified: ",
519	                             sizeof("Last-Modified: ") - 1);
520	        b->last = ngx_http_time(b->last, r->headers_out.last_modified_time);
521	
522	        *b->last++ = CR; *b->last++ = LF;
523	    }
524	
525	    if (host.data) {
526	
527	        p = b->last + sizeof("Location: ") - 1;
528	
529	        b->last = ngx_cpymem(b->last, "Location: http",
530	                             sizeof("Location: http") - 1);
531	
532	#if (NGX_HTTP_SSL)
533	        if (c->ssl) {
534	            *b->last++ ='s';
535	        }
536	#endif
537	
538	        *b->last++ = ':'; *b->last++ = '/'; *b->last++ = '/';
539	        b->last = ngx_copy(b->last, host.data, host.len);
540	
541	        if (port) {
542	            b->last = ngx_sprintf(b->last, ":%ui", port);
543	        }
544	
545	        b->last = ngx_copy(b->last, r->headers_out.location->value.data,
546	                           r->headers_out.location->value.len);
547	
548	        /* update r->headers_out.location->value for possible logging */
549	
550	        r->headers_out.location->value.len = b->last - p;
551	        r->headers_out.location->value.data = p;
552	        ngx_str_set(&r->headers_out.location->key, "Location");
553	
554	        *b->last++ = CR; *b->last++ = LF;
555	    }
556	
557	    if (r->chunked) {
558	        b->last = ngx_cpymem(b->last, "Transfer-Encoding: chunked" CRLF,
559	                             sizeof("Transfer-Encoding: chunked" CRLF) - 1);
560	    }
561	
562	    if (r->headers_out.status == NGX_HTTP_SWITCHING_PROTOCOLS) {
563	        b->last = ngx_cpymem(b->last, "Connection: upgrade" CRLF,
564	                             sizeof("Connection: upgrade" CRLF) - 1);
565	
566	    } else if (r->keepalive) {
567	        b->last = ngx_cpymem(b->last, "Connection: keep-alive" CRLF,
568	                             sizeof("Connection: keep-alive" CRLF) - 1);
569	
570	        if (clcf->keepalive_header) {
571	            b->last = ngx_sprintf(b->last, "Keep-Alive: timeout=%T" CRLF,
572	                                  clcf->keepalive_header);
573	        }
574	
575	    } else {
576	        b->last = ngx_cpymem(b->last, "Connection: close" CRLF,
577	                             sizeof("Connection: close" CRLF) - 1);
578	    }
579	
580	#if (NGX_HTTP_GZIP)
581	    if (r->gzip_vary) {
582	        b->last = ngx_cpymem(b->last, "Vary: Accept-Encoding" CRLF,
583	                             sizeof("Vary: Accept-Encoding" CRLF) - 1);
584	    }
585	#endif
586	
587	    part = &r->headers_out.headers.part;
588	    header = part->elts;
589	
590	    for (i = 0; /* void */; i++) {
591	
592	        if (i >= part->nelts) {
593	            if (part->next == NULL) {
594	                break;
595	            }
596	
597	            part = part->next;
598	            header = part->elts;
599	            i = 0;
600	        }
601	
602	        if (header[i].hash == 0) {
603	            continue;
604	        }
605	
606	        b->last = ngx_copy(b->last, header[i].key.data, header[i].key.len);
607	        *b->last++ = ':'; *b->last++ = ' ';
608	
609	        b->last = ngx_copy(b->last, header[i].value.data, header[i].value.len);
610	        *b->last++ = CR; *b->last++ = LF;
611	    }
612	
613	    ngx_log_debug2(NGX_LOG_DEBUG_HTTP, c->log, 0,
614	                   "%*s", (size_t) (b->last - b->pos), b->pos);
615	
616	    /* the end of HTTP header */
617	    *b->last++ = CR; *b->last++ = LF;
618	
619	    r->header_size = b->last - b->pos;
620	
621	    if (r->header_only) {
622	        b->last_buf = 1;
623	    }
624	
625	    out.buf = b;
626	    out.next = NULL;
627	
628	    return ngx_http_write_filter(r, &out);
629	}
630	
631	
632	static ngx_int_t
633	ngx_http_early_hints_filter(ngx_http_request_t *r)
634	{
635	    size_t            len;
636	    ngx_buf_t        *b;
637	    ngx_uint_t        i;
638	    ngx_chain_t       out;
639	    ngx_list_part_t  *part;
640	    ngx_table_elt_t  *header;
641	
642	    if (r != r->main) {
643	        return NGX_OK;
644	    }
645	
646	    if (r->http_version < NGX_HTTP_VERSION_11) {
647	        return NGX_OK;
648	    }
649	
650	    len = 0;
651	
652	    part = &r->headers_out.headers.part;
653	    header = part->elts;
654	
655	    for (i = 0; /* void */; i++) {
656	
657	        if (i >= part->nelts) {
658	            if (part->next == NULL) {
659	                break;
660	            }
661	
662	            part = part->next;
663	            header = part->elts;
664	            i = 0;
665	        }
666	
667	        if (header[i].hash == 0) {
668	            continue;
669	        }
670	
671	        len += header[i].key.len + sizeof(": ") - 1 + header[i].value.len
672	               + sizeof(CRLF) - 1;
673	    }
674	
675	    if (len == 0) {
676	        return NGX_OK;
677	    }
678	
679	    len += ngx_http_early_hints_status_line.len
680	           /* the end of the early hints */
681	           + sizeof(CRLF) - 1;
682	
683	    b = ngx_create_temp_buf(r->pool, len);
684	    if (b == NULL) {
685	        return NGX_ERROR;
686	    }
687	
688	    b->last = ngx_copy(b->last, ngx_http_early_hints_status_line.data,
689	                       ngx_http_early_hints_status_line.len);
690	
691	    part = &r->headers_out.headers.part;
692	    header = part->elts;
693	
694	    for (i = 0; /* void */; i++) {
695	
696	        if (i >= part->nelts) {
697	            if (part->next == NULL) {
698	                break;
699	            }
700	
701	            part = part->next;
702	            header = part->elts;
703	            i = 0;
704	        }
705	
706	        if (header[i].hash == 0) {
707	            continue;
708	        }
709	
710	        b->last = ngx_copy(b->last, header[i].key.data, header[i].key.len);
711	        *b->last++ = ':'; *b->last++ = ' ';
712	
713	        b->last = ngx_copy(b->last, header[i].value.data, header[i].value.len);
714	        *b->last++ = CR; *b->last++ = LF;
715	    }
716	
717	    ngx_log_debug2(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
718	                   "%*s", (size_t) (b->last - b->pos), b->pos);
719	
720	    /* the end of HTTP early hints */
721	    *b->last++ = CR; *b->last++ = LF;
722	
723	    r->header_size = b->last - b->pos;
724	
725	    b->flush = 1;
726	
727	    out.buf = b;
728	    out.next = NULL;
729	
730	    return ngx_http_write_filter(r, &out);
731	}
732	
733	
734	static ngx_int_t
735	ngx_http_header_filter_init(ngx_conf_t *cf)
736	{
737	    ngx_http_top_header_filter = ngx_http_header_filter;
738	    ngx_http_top_early_hints_filter = ngx_http_early_hints_filter;
739	
740	    return NGX_OK;
741	}
